message.content:
{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem is a topological embedding task where we need to shrink colored regions to single cells or small clusters while maintaining connectivity and adjacency. This requires graph theory and spatial layout optimization.",
  "helpers": [
    {
      "label": "graph_extractor",
      "instructions": "Analyze the input 50x50 grid to construct a graph where each node represents a color (1 to M). For each node, determine its connectivity (which colors it is adjacent to) and its original connectivity (ensure each color's cells form a connected component). Output a list of adjacency relations and a list of colors."
    },
    {
      "label": "layout_optimizer",
      "instructions": "Given a graph of M colors and their adjacency requirements, find a way to assign each color to a single coordinate (x, y) on a 50x50 grid such that if two colors are adjacent in the graph, their assigned coordinates are orthogonally adjacent (up, down, left, or right) in the grid. The goal is to minimize the number of cells used to maximize the number of 0 cells."
    },
    {
      "label": "grid_generator",
      "instructions": "Take the optimized coordinates for each color and construct a 50x50 grid. Fill the assigned coordinates with their respective color IDs and all other cells with 0. Ensure the output is a valid 50x50 grid of integers."
    }
  ],
  "synthesis_brief": "Combine the graph adjacency list from the extractor with the optimized coordinate mapping from the layout optimizer to produce the final 50x50 grid via the generator."
}

